mapper.select:
		/* oms-master-owOrType-sql-oracle.xml selectOrTypeCount */
        SELECT COUNT(1)
          FROM TORDER_MST_EXTERN A


			 	   #{SEARCH_CONDITION}

/* oms-master-owOrType-sql-oracle.xml selectOrTypeList */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' AS CHK , A.OWKEY , O.OWNM AS OWKEYNM , A.EXTORDERTYPECD , A.EXTORDERTYPENM , COALESCE(A.DELYN, 'N') AS DELYN , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY --, COALESCE(A.PREORDERYN, 'N') AS PREORDERYN FROM TORDER_MST_EXTERN A LEFT JOIN TORDER_MST_OW O ON A.OWKEY = O.OWKEY WHERE 1=1
AND #{SEARCH_CONDITION}
AND A.OWKEY = #{owkey}
AND A.EXTORDERTYPECD = #{extordertypecd}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY A.EXTORDERTYPECD
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

	/* oms-master-owOrType-sql-oracle.xml checkOrTypeInfo */
		SELECT COUNT(1)
		  FROM TORDER_MST_EXTERN	
    	 WHERE OWKEY = #{owkey}
    	   AND EXTORDERTYPECD = #{extordertypecd}

mapper.insert:
/* oms-master-owOrType-sql-oracle.xml insertOrType */
	INSERT INTO TORDER_MST_EXTERN
	(
	      OWKEY
	    , EXTORDERTYPECD
	    , EXTORDERTYPENM
	    , DELYN
	    , INSERTDATE
	    , INSERTURKEY
	    , UPDATEDATE
	    , UPDATEURKEY
	    --, PREORDERYN
	)
	VALUES
	(
	      #{owkey}
	    , #{extordertypecd}
	    , #{extordertypenm}
	    , #{delyn}
	    , #{sysdate}
	    , #{surkey}
	    , #{sysdate}
	    , #{surkey}
	)

mapper.update:
/* oms-master-owOrType-sql-oracle.xml updateOrType */
	UPDATE TORDER_MST_EXTERN
	   SET EXTORDERTYPENM = #{extordertypenm}
	     , DELYN        = #{delyn}
	     , UPDATEDATE   = #{sysdate}
	     , UPDATEURKEY  = #{surkey}
	 WHERE OWKEY = #{owkey}
	   AND EXTORDERTYPECD = #{extordertypecd}
